CREATE VIEW `ads_sensors_cd_video_startwatching_big_dipper_view` (`dt` COMMENT "日期", `id` COMMENT "主键", `rid` COMMENT "记录ID", `track_id` COMMENT "track_id", `event` COMMENT "事件", `event_tm` COMMENT "事件时间", `app_channel` COMMENT "渠道编号", `app_id` COMMENT "app_id", `app_lang_id` COMMENT "界面语言", `device_lang` COMMENT "设备语言", `login_id` COMMENT "用户ID", `product_id` COMMENT "产品ID", `app_version` COMMENT "应用版本", `os` COMMENT "操作系统", `core` COMMENT "core版本，目前有1，2，3", `current_language2` COMMENT "注册时语言", `ip` COMMENT "IP", `city` COMMENT "城市", `province` COMMENT "省份", `country` COMMENT "国家", `shortplay_id` COMMENT "	短剧ID", `if_first_watch_shortplay` COMMENT "短剧是否首次观看", `episode_id` COMMENT "剧集ID", `watch_episode_sort` COMMENT "内容页剧集ID序号", `watch_source_id` COMMENT "观看来源控件id", `watch_source_name` COMMENT "观看来源控件名称", `watch_source_page_id` COMMENT "观看来源页面id", `watch_source_page_name` COMMENT "观看来源页面名称", `watch_speeds` COMMENT "观看倍速", `send_id` COMMENT "发送ID", `activity_link` COMMENT "活动链路", `etl_tm` COMMENT "清洗时间") AS SELECT `ods_log`.`a`.`dt`, `ods_log`.`a`.`id`, `ods_log`.`a`.`rid`, `ods_log`.`a`.`track_id`, `ods_log`.`a`.`event`, `ods_log`.`a`.`event_tm`, `ods_log`.`a`.`app_channel`, `ods_log`.`a`.`app_id`, `ods_log`.`a`.`app_lang_id`, `ods_log`.`a`.`device_lang`, `ods_log`.`a`.`login_id`, `ods_log`.`a`.`product_id`, `ods_log`.`a`.`app_version`, `ods_log`.`a`.`os`, CAST((substring(`ods_log`.`a`.`app_id`, 4, 3)) AS INT) AS `core`, `ods`.`b`.`CurrentLanguage2` AS `current_language2`, `ods_log`.`a`.`ip`, `ods_log`.`a`.`city`, `ods_log`.`a`.`province`, `ods_log`.`a`.`country`, `ods_log`.`a`.`shortplay_id`, `ods_log`.`a`.`if_first_watch_shortplay`, `ods_log`.`a`.`episode_id`, `ods_log`.`a`.`watch_episode_sort`, `ods_log`.`a`.`watch_source_id`, `ods_log`.`a`.`watch_source_name`, `ods_log`.`a`.`watch_source_page_id`, `ods_log`.`a`.`watch_source_page_name`, `ods_log`.`a`.`watch_speeds`, `ods_log`.`a`.`send_id`, `ods_log`.`a`.`activity_link`, `ods_log`.`a`.`etl_tm`
FROM `ods_log`.`ods_sensors_cd_video_startwatching_big_dipper` AS `a` LEFT OUTER JOIN `ods`.`ods_tidb_short_video_accountinfo` AS `b` ON `ods_log`.`a`.`login_id` = `ods`.`b`.`Id`;